+fn format_alloc_summary(stats: Option<&crate::bench::runner::BenchAllocStats>) -> String {
+    match stats {
+        Some(stats) => format!(
+            " alloc_avg={:.1} bytes_avg={}",
+            stats.avg_allocations,
+            format_bytes(stats.avg_bytes_allocated)
+        ),
+        None => String::new(),
+    }
