+fn load_baseline(path: &Path) -> io::Result<BenchRunSummary> {
+    let data = fs::read(path)?;
+    let summary: BenchRunSummary = serde_json::from_slice(&data)
+        .map_err(|err| io::Error::new(io::ErrorKind::InvalidData, err.to_string()))?;
