+    fn fmt(&self, f: &mut std::fmt::Formatter<'_>) -> std::fmt::Result {
+        let reg_count = self.registrations.lock().len();
+        f.debug_struct("KqueueReactor")
+            .field("registration_count", &reg_count)
+            .finish_non_exhaustive()
+    }
+}
